(game "Secret Mottled Eagle  Secret Phase"
    (players 2)

    (equipment
        (board (square 5))
    )

    (rules

        (start

        )


        (play

            (repeat (P1 P2)
                (place
                    (destination
                        (and
                            empty
                            (not (adjacent (occupied opponent)))
                        )
                    )
                    (effects
                        (capture (custodial any) increment_score:true)
                    )
                )
            )




            (once_through (P1 P2)
                (place
                    (destination
                        (and
                            empty
                            (not (adjacent (occupied opponent)))
                        )
